1	/**
2	 * Scroll System Setup
3	 * - Lenis smooth scroll initialization
4	 * - GSAP ScrollTrigger proxying
5	 * - Viewport unit calculation (--vh, --vw)
6	 * - Initial load animation sequence (.-loaded, .-ready classes)
7	 */
8	
9	let lenis = null;
10	
11	function initLenis() {
12	  // Initialize Lenis smooth scroll
13	  lenis = new Lenis({
14	    duration: 1.2,
15	    easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
16	    direction: 'vertical',
17	    gestureDirection: 'vertical',
18	    smooth: true,
19	  });
20	
21	  // Proxy GSAP to use Lenis for scroll
22	  lenis.on('scroll', ({ velocity, direction, progress }) => {
23	    ScrollTrigger.update();
24	  });
25	
26	  // Update GSAP on each Lenis frame
27	  const raf = (time) => {
28	    lenis.raf(time);
29	    requestAnimationFrame(raf);
30	  };
31	  requestAnimationFrame(raf);
32	
33	  // Sync GSAP's internal scroll
34	  gsap.ticker.add((time) => {
35	    lenis.raf(time * 1000);
36	  });
37	}
38	
39	function updateViewportUnits() {
40	  const vh = window.innerHeight * 0.01;
41	  const vw = window.innerWidth * 0.01;
42	  document.documentElement.style.setProperty('--vh', `${vh}px`);
43	  document.documentElement.style.setProperty('--vw', `${vw}px`);
44	}
45	
46	function initScrollSystem() {
47	  // Initialize Lenis
48	  initLenis();
49	
50	  // Set initial viewport units
51	  updateViewportUnits();
52	
53	  // Update on resize
54	  let resizeTimeout;
55	  window.addEventListener('resize', () => {
56	    clearTimeout(resizeTimeout);
57	    resizeTimeout = setTimeout(updateViewportUnits, 200);
58	  });
59	
60	  // Set up GSAP ScrollTrigger
61	  ScrollTrigger.scrollerProxy(document.documentElement, {
62	    scrollTop(value) {
63	      if (arguments.length) {
64	        lenis.scrollTo(value, { immediate: true });
65	      }
66	      return lenis.actualScroll;
67	    },
68	    getBoundingClientRect() {
69	      return {
70	        top: 0,
71	        left: 0,
72	        width: window.innerWidth,
73	        height: window.innerHeight,
74	      };
75	    },
76	    pinType: 'transform',
77	  });
78	
79	  // Initial load sequence
80	  const html = document.documentElement;
81	
82	  // Add .-loaded class after a small delay (CSS transitions unlock)
83	  setTimeout(() => {
84	    html.classList.add('-loaded');
85	  }, 100);
86	
87	  // Add .-ready class after content is laid out
88	  setTimeout(() => {
89	    html.classList.add('-ready');
90	  }, 1300);
91	}
92	
93	// Start on DOM ready
94	if (document.readyState === 'loading') {
95	  document.addEventListener('DOMContentLoaded', initScrollSystem);
96	} else {
97	  initScrollSystem();
98	}
99	
100	export { lenis, updateViewportUnits };
