1	/* Design Tokens — The Obsidian Assembly Clone */
2	
3	:root {
4	  /* ===== COLORS ===== */
5	  --c-black: #151415;
6	  --c-black-rgb: 21, 20, 21;
7	  --c-white: #fff;
8	  --c-white-rgb: 255, 255, 255;
9	  --c-grey: #3f383c;
10	  --c-grey-rgb: 63, 56, 60;
11	  --c-stone: #242324;
12	  --c-stone-rgb: 36, 35, 36;
13	  --c-yellow: #c9a96e;
14	  --c-yellow-rgb: 201, 169, 110;
15	  --c-brown: #6b4226;
16	  --c-brown-rgb: 107, 66, 38;
17	  --c-purple: #7a6b7a;
18	  --c-grey-dark: #2a2428;
19	  --c-berry: #8b3a62;
20	
21	  /* ===== TYPOGRAPHY SCALE ===== */
22	  --type-step: 1.25;
23	  --body-font-size: 1rem;
24	  --body-line-height: 1.3;
25	
26	  /* Spacing derived from type scale */
27	  --p: 1rem;
28	  --m: calc(var(--p) / var(--type-step));
29	  --mm: calc(var(--m) / var(--type-step));
30	
31	  /* Font sizes (heading/display) */
32	  --h6: calc(var(--p) * var(--type-step));
33	  --h5: calc(var(--h6) * var(--type-step));
34	  --h4: calc(var(--h5) * var(--type-step));
35	  --h3: calc(var(--h4) * var(--type-step));
36	  --h2: calc(var(--h3) * var(--type-step));
37	  --h1: calc(var(--h2) * var(--type-step));
38	  --h0: calc(var(--h1) * var(--type-step));
39	  --large: max(calc(var(--h0) * var(--type-step) * var(--type-step)), 12.5vw);
40	
41	  /* Line heights */
42	  --line-height-step: var(--body-line-height) / var(--type-step);
43	  --h0-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
44	  --h1-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
45	  --h2-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
46	  --h3-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
47	  --h4-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -3));
48	  --h5-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -2));
49	  --h6-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -1));
50	  --large-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -13));
51	
52	  /* ===== FONTS ===== */
53	  --font-t-1: "Cormorant Garamond", serif;
54	  --font-t-2: "DM Serif Display", serif;
55	  --font-b-medium: "Inter", system-ui, -apple-system, sans-serif;
56	  --font-b-regular: "Inter", system-ui, -apple-system, sans-serif;
57	  --font: var(--font-b-regular);
58	
59	  /* ===== GRID SYSTEM ===== */
60	  --g-columns: 12;
61	  --g-gap: 1rem;
62	  --g-margin: 1rem;
63	
64	  /* ===== VIEWPORT UNITS ===== */
65	  /* Set by js/scroll.js on mount and resize */
66	  --vh: 1vh;
67	  --vw: 1vw;
68	
69	  /* ===== EASING / TIMING ===== */
70	  --f-cubic: cubic-bezier(0.25, 0.1, 0.25, 1);
71	  --f-fast: cubic-bezier(0.22, 0.31, 0, 1);
72	  --f-cubic-in: cubic-bezier(0.55, 0, 1, 0.45);
73	  --f-smooth: cubic-bezier(0.45, 0.05, 0.55, 0.95);
74	}
75	
76	/* Responsive scaling */
77	@media (max-width: 1024px) {
78	  :root {
79	    --large: var(--h0);
80	    --g-gap: 0.75rem;
81	    --g-margin: 0.75rem;
82	  }
83	}
84	
85	@media (max-width: 640px) {
86	  :root {
87	    --body-font-size: 0.875rem;
88	    --g-gap: 0.5rem;
89	    --g-margin: 0.5rem;
90	  }
91	}
